def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 3:
            priorities[i] = ratio ** 5 - np.sqrt(ratio) + np.exp(-ratio)
        elif ratio == 3:
            priorities[i] = 2.0
        elif 2 < ratio < 3:
            priorities[i] = (ratio - 2) ** 3 * 15 + np.log1p(ratio)
        elif ratio == 2:
            priorities[i] = 1.0
        elif 1 < ratio < 2:
            priorities[i] = (ratio - 1) ** 2 * 12
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 8):
                term = ((1 - ratio) ** j) / (j ** 3)
                if j % 3 == 0:
                    term *= 1.5
                elif j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.7
                score += term
            if bin_capacity < item * 1.2:
                score *= 3
            elif bin_capacity > item * 4:
                score /= 3
            mod_sum = 0
            for k in range(1, 6):
                mod_val = (bin_capacity % (item + k)) / (item + k)
                if mod_val > 0.5:
                    mod_val *= 1.3
                else:
                    mod_val *= 0.9
                mod_sum += mod_val * 0.05 * k
            score += mod_sum
            if bin_capacity % 2 == 0:
                score += 0.1 * (bin_capacity / (item + 1))
            else:
                score -= 0.05 * (item / (bin_capacity + 1))
            priorities[i] = max(score, 0)
    return priorities
